import java.util.concurrent.atomic.AtomicInteger;

public class SynchronizationDemo {

    // ── BROKEN: race condition ──────────────────────────────────────────
    static int unsafeCounter = 0;
    static void unsafeIncrement() { unsafeCounter++; } // read-modify-write: NOT atomic

    // ── FIX 1: synchronized method ─────────────────────────────────────
    static int syncCounter = 0;
    static synchronized void syncIncrement() { syncCounter++; }

    // ── FIX 2: AtomicInteger (lock-free CAS) ───────────────────────────
    static AtomicInteger atomicCounter = new AtomicInteger(0);

    // ── FIX 3: volatile — visibility only, NOT atomicity ───────────────
    // volatile guarantees all threads see the latest write.
    // But volatile does NOT make compound operations (++) atomic.
    static volatile boolean shutdownFlag = false;

    public static void main(String[] args) throws InterruptedException {
        int THREADS = 4, OPS = 25_000;

        // Race condition demo
        Thread[] unsafe = new Thread[THREADS];
        for (int i = 0; i < THREADS; i++)
            unsafe[i] = new Thread(() -> { for (int j=0;j<OPS;j++) unsafeIncrement(); });
        for (Thread t : unsafe) t.start();
        for (Thread t : unsafe) t.join();
        System.out.println("Unsafe  (expected " + THREADS*OPS + "): " + unsafeCounter);
        // Likely LESS than 100000 — lost updates

        // Synchronized demo
        Thread[] synced = new Thread[THREADS];
        for (int i = 0; i < THREADS; i++)
            synced[i] = new Thread(() -> { for (int j=0;j<OPS;j++) syncIncrement(); });
        for (Thread t : synced) t.start();
        for (Thread t : synced) t.join();
        System.out.println("Synced  (expected " + THREADS*OPS + "): " + syncCounter);
        // Always 100000

        // Atomic demo
        Thread[] atomics = new Thread[THREADS];
        for (int i = 0; i < THREADS; i++)
            atomics[i] = new Thread(() -> { for (int j=0;j<OPS;j++) atomicCounter.incrementAndGet(); });
        for (Thread t : atomics) t.start();
        for (Thread t : atomics) t.join();
        System.out.println("Atomic  (expected " + THREADS*OPS + "): " + atomicCounter.get());
        // Always 100000, faster than synchronized

        // Volatile shutdown flag — correct usage
        Thread worker = new Thread(() -> {
            int work = 0;
            while (!shutdownFlag) { work++; } // always reads latest value
            System.out.println("Worker stopped after " + work + " iterations");
        });
        worker.start();
        Thread.sleep(10);
        shutdownFlag = true; // visible to worker thread immediately
        worker.join();
    }
}

import java.util.concurrent.locks.*;
import java.util.concurrent.*;

public class ReentrantLockDemo {

    // ── Producer-Consumer with Condition ───────────────────────────────
    static class BoundedBuffer<T> {
        private final Object[] items;
        private int head, tail, count;
        private final ReentrantLock lock    = new ReentrantLock();
        private final Condition    notFull  = lock.newCondition();
        private final Condition    notEmpty = lock.newCondition();

        BoundedBuffer(int capacity) { items = new Object[capacity]; }

        @SuppressWarnings("unchecked")
        public T take() throws InterruptedException {
            lock.lock();
            try {
                while (count == 0) notEmpty.await(); // releases lock, waits
                T item = (T) items[head];
                items[head] = null;
                head = (head + 1) % items.length;
                count--;
                notFull.signal(); // wake one waiting producer
                return item;
            } finally { lock.unlock(); } // ALWAYS in finally
        }

        public void put(T item) throws InterruptedException {
            lock.lock();
            try {
                while (count == items.length) notFull.await();
                items[tail] = item;
                tail = (tail + 1) % items.length;
                count++;
                notEmpty.signal();
            } finally { lock.unlock(); }
        }
    }

    // ── Deadlock prevention: always lock in the same order ─────────────
    static class Account {
        final int id;
        double balance;
        final ReentrantLock lock = new ReentrantLock();
        Account(int id, double balance) { this.id = id; this.balance = balance; }
    }

    static void transfer(Account from, Account to, double amount)
            throws InterruptedException {
        // Always acquire locks in ID order — prevents deadlock
        Account first  = from.id < to.id ? from : to;
        Account second = from.id < to.id ? to   : from;
        first.lock.lock();
        try {
            second.lock.lock();
            try {
                if (from.balance >= amount) {
                    from.balance -= amount;
                    to.balance   += amount;
                }
            } finally { second.lock.unlock(); }
        } finally { first.lock.unlock(); }
    }

    public static void main(String[] args) throws InterruptedException {
        BoundedBuffer<Integer> buffer = new BoundedBuffer<>(5);
        Thread producer = new Thread(() -> {
            try {
                for (int i = 1; i <= 10; i++) { buffer.put(i); System.out.print("P"+i+" "); }
            } catch (InterruptedException ignored) {}
        });
        Thread consumer = new Thread(() -> {
            try {
                for (int i = 0; i < 10; i++) System.out.print("C"+buffer.take()+" ");
            } catch (InterruptedException ignored) {}
        });
        producer.start(); consumer.start();
        producer.join(); consumer.join();
        System.out.println("\nDone");

        Account a = new Account(1, 1000);
        Account b = new Account(2, 500);
        Thread t1 = new Thread(() -> { try { transfer(a, b, 200); } catch (InterruptedException ignored) {} });
        Thread t2 = new Thread(() -> { try { transfer(b, a, 100); } catch (InterruptedException ignored) {} });
        t1.start(); t2.start(); t1.join(); t2.join();
        System.out.println("a=" + a.balance + " b=" + b.balance); // a=900.0 b=600.0
    }
}

import java.util.concurrent.*;
import java.util.*;
import java.util.stream.*;

public class ExecutorServiceDemo {

    static int expensiveCompute(int n) {
        try { Thread.sleep(10); } catch (InterruptedException e) { Thread.currentThread().interrupt(); }
        return n * n;
    }

    public static void main(String[] args) throws InterruptedException, ExecutionException {

        // ── Fixed thread pool ──────────────────────────────────────────
        ExecutorService pool = Executors.newFixedThreadPool(4);

        // submit() returns Future<T> — non-blocking
        List<Future<Integer>> futures = new ArrayList<>();
        for (int i = 1; i <= 10; i++) {
            final int n = i;
            futures.add(pool.submit(() -> expensiveCompute(n)));
        }

        // Collect results — blocks until each result is available
        List<Integer> results = new ArrayList<>();
        for (Future<Integer> f : futures) results.add(f.get());
        System.out.println(results); // [1, 4, 9, 16, 25, 36, 49, 64, 81, 100]

        // ── invokeAll — submit batch, wait for ALL ─────────────────────
        List<Callable<Integer>> tasks = IntStream.rangeClosed(1, 5)
            .mapToObj(n -> (Callable<Integer>) () -> expensiveCompute(n))
            .collect(Collectors.toList());
        List<Future<Integer>> allFutures = pool.invokeAll(tasks); // blocks until all done
        System.out.println(allFutures.stream().map(f -> {
            try { return f.get(); } catch (Exception e) { return -1; }
        }).collect(Collectors.toList())); // [1, 4, 9, 16, 25]

        // ── Scheduled executor ─────────────────────────────────────────
        ScheduledExecutorService scheduler = Executors.newScheduledThreadPool(2);
        scheduler.scheduleAtFixedRate(
            () -> System.out.println("Heartbeat at " + System.currentTimeMillis()),
            0, 100, TimeUnit.MILLISECONDS); // initial delay 0, period 100ms

        Thread.sleep(350); // let it run 3-4 times
        scheduler.shutdown();

        // ── Graceful shutdown ──────────────────────────────────────────
        pool.shutdown(); // stop accepting new tasks
        boolean done = pool.awaitTermination(5, TimeUnit.SECONDS);
        System.out.println("Pool terminated: " + done);

        // ── Custom thread pool with named threads ─────────────────────
        ThreadFactory namedFactory = r -> {
            Thread t = new Thread(r);
            t.setName("worker-" + t.getId());
            t.setDaemon(true); // dies when main thread dies
            return t;
        };
        ExecutorService custom = new ThreadPoolExecutor(
            2, 4,          // corePoolSize, maxPoolSize
            60, TimeUnit.SECONDS,     // keepAlive for idle threads
            new LinkedBlockingQueue<>(100), // bounded work queue
            namedFactory
        );
        custom.submit(() -> System.out.println("Task on: " + Thread.currentThread().getName()));
        custom.shutdown();
        custom.awaitTermination(1, TimeUnit.SECONDS);
    }
}

import java.util.concurrent.*;
import java.util.*;
import java.util.stream.*;

public class CompletableFutureDemo {

    static String fetchUser(int id) {
        sleep(50); return "User" + id;
    }
    static List<String> fetchOrders(String user) {
        sleep(50); return List.of(user+"-order1", user+"-order2");
    }
    static double fetchPrice(String orderId) {
        sleep(30); return orderId.hashCode() % 100 * 1.5;
    }
    static void sleep(long ms) { try{Thread.sleep(ms);}catch(InterruptedException e){Thread.currentThread().interrupt();} }

    public static void main(String[] args) throws Exception {

        // ── Basic async chain ──────────────────────────────────────────
        CompletableFuture<List<String>> ordersFuture = CompletableFuture
            .supplyAsync(() -> fetchUser(42))          // runs on ForkJoinPool
            .thenApply(user -> fetchOrders(user))      // transform result
            .thenApply(orders -> orders.stream()       // another transform
                .map(String::toUpperCase).collect(Collectors.toList()));

        System.out.println(ordersFuture.join()); // blocks and gets result

        // ── thenCompose — flat-map for futures ─────────────────────────
        CompletableFuture<List<String>> cf = CompletableFuture
            .supplyAsync(() -> fetchUser(1))
            .thenCompose(user ->                       // returns a new CF
                CompletableFuture.supplyAsync(() -> fetchOrders(user)));

        // ── Parallel execution then combine ───────────────────────────
        long start = System.currentTimeMillis();
        CompletableFuture<String> u1 = CompletableFuture.supplyAsync(() -> fetchUser(1));
        CompletableFuture<String> u2 = CompletableFuture.supplyAsync(() -> fetchUser(2));
        CompletableFuture<String> u3 = CompletableFuture.supplyAsync(() -> fetchUser(3));

        // Wait for all three in parallel
        CompletableFuture<Void> all = CompletableFuture.allOf(u1, u2, u3);
        all.join(); // blocks until all complete
        List<String> users = List.of(u1.join(), u2.join(), u3.join());
        System.out.println("Parallel fetch: " + (System.currentTimeMillis()-start) + "ms — " + users);
        // ~50ms (parallel) not ~150ms (sequential)

        // ── Error handling ─────────────────────────────────────────────
        CompletableFuture<String> risky = CompletableFuture
            .supplyAsync(() -> { throw new RuntimeException("Service down"); })
            .exceptionally(ex -> "fallback-user")   // catches exception, provides default
            .thenApply(user -> user.toUpperCase());

        System.out.println(risky.join()); // FALLBACK-USER

        // ── thenCombine — merge two independent results ────────────────
        CompletableFuture<String> nameF  = CompletableFuture.supplyAsync(() -> { sleep(30); return "Alice"; });
        CompletableFuture<Integer> ageF  = CompletableFuture.supplyAsync(() -> { sleep(40); return 30; });
        String profile = nameF.thenCombine(ageF, (name, age) -> name + " age " + age).join();
        System.out.println(profile); // Alice age 30
    }
}

import java.util.concurrent.*;
import java.util.*;

public class ForkJoinDemo {

    // ── Parallel sum using RecursiveTask ───────────────────────────────
    static class ParallelSum extends RecursiveTask<Long> {
        private static final int THRESHOLD = 1000;
        private final long[] array;
        private final int from, to;

        ParallelSum(long[] array, int from, int to) {
            this.array = array; this.from = from; this.to = to;
        }

        @Override
        protected Long compute() {
            int size = to - from;
            if (size <= THRESHOLD) {
                // Base case: compute directly
                long sum = 0;
                for (int i = from; i < to; i++) sum += array[i];
                return sum;
            }
            // Recursive case: split in half
            int mid = from + size / 2;
            ParallelSum left  = new ParallelSum(array, from, mid);
            ParallelSum right = new ParallelSum(array, mid, to);
            left.fork();            // schedule left on ForkJoinPool asynchronously
            long rightResult = right.compute(); // compute right on current thread
            long leftResult  = left.join();     // wait for left
            return leftResult + rightResult;
        }
    }

    // ── Work-stealing in action ────────────────────────────────────────
    public static void main(String[] args) throws Exception {
        int N = 10_000_000;
        long[] array = new long[N];
        Arrays.fill(array, 1L); // sum should be N

        // Sequential
        long t1 = System.currentTimeMillis();
        long seqSum = 0;
        for (long v : array) seqSum += v;
        System.out.println("Sequential: " + (System.currentTimeMillis()-t1) + "ms sum=" + seqSum);

        // ForkJoin
        ForkJoinPool pool = ForkJoinPool.commonPool();
        long t2 = System.currentTimeMillis();
        long parSum = pool.invoke(new ParallelSum(array, 0, N));
        System.out.println("ForkJoin:   " + (System.currentTimeMillis()-t2) + "ms sum=" + parSum);
        System.out.println("Results match: " + (seqSum == parSum)); // true

        // ── Parallel array processing via streams (uses ForkJoinPool) ──
        long t3 = System.currentTimeMillis();
        long streamSum = Arrays.stream(array).parallel().sum();
        System.out.println("ParallelStream: " + (System.currentTimeMillis()-t3) + "ms sum=" + streamSum);

        // ── RecursiveAction — no return value ──────────────────────────
        // (e.g., parallel array fill, parallel sort)
        ForkJoinPool custom = new ForkJoinPool(2); // 2 worker threads
        custom.submit(() -> System.out.println(
            "Workers: " + custom.getPoolSize() + " Parallelism: " + custom.getParallelism())
        ).get();
        custom.shutdown();
    }
}

