        for (Thread t : ts) t.start(); for (Thread t : ts) t.join();
        System.out.println("Sync: " + sc.getCount() + " expected " + THREADS*OPS);

        AtomicCounter ac = new AtomicCounter();
        Thread[] ta = new Thread[THREADS];
