public class Q3 {
    static final ReentrantLock lockA = new ReentrantLock();
    static final ReentrantLock lockB = new ReentrantLock();

    static void task1() {
        lockA.lock();
        try { Thread.yield(); lockB.lock();
            try { System.out.println("Task1 done"); } finally { lockB.unlock(); }
        } finally { lockA.unlock(); }
    }

    static void task2() { // BROKEN — opposite order
        lockB.lock();
        try { lockA.lock();
            try { System.out.println("Task2 done"); } finally { lockA.unlock(); }
        } finally { lockB.unlock(); }
    }

    static void task2Fixed() { // FIXED — same order as task1
        lockA.lock(); // acquire A first
        try { lockB.lock();
            try { System.out.println("Task2Fixed done"); } finally { lockB.unlock(); }
        } finally { lockA.unlock(); }
    }

    public static void main(String[] args) throws InterruptedException {
