import java.util.*;
import java.util.concurrent.*;

public class Q4 {
    static final int THRESHOLD = 1000;

    static class ParallelMergeSort extends RecursiveAction {
        private final int[] arr; private final int from, to;
        ParallelMergeSort(int[] arr, int from, int to) { this.arr=arr; this.from=from; this.to=to; }

        @Override
        protected void compute() {
            if (to - from <= THRESHOLD) { Arrays.sort(arr, from, to); return; }
            int mid = from + (to - from) / 2;
            ParallelMergeSort left = new ParallelMergeSort(arr, from, mid);
            left.fork();
            new ParallelMergeSort(arr, mid, to).compute();
            left.join();
            merge(mid);
        }

        private void merge(int mid) {
            int[] left  = Arrays.copyOfRange(arr, from, mid);
            int[] right = Arrays.copyOfRange(arr, mid, to);
            int i=0, j=0, k=from;
            while (i<left.length && j<right.length)
                arr[k++] = left[i]<=right[j] ? left[i++] : right[j++];
            while (i<left.length)  arr[k++]=left[i++];
            while (j<right.length) arr[k++]=right[j++];
        }
    }

    public static void main(String[] args) {
        int[] arr = new int[1_000_000];
        for (int i=0;i<arr.length;i++) arr[i]=(int)(Math.random()*1_000_000);
        int[] copy = arr.clone();
        long t1 = System.currentTimeMillis();
        Arrays.sort(copy);
        System.out.println("Sequential: "+(System.currentTimeMillis()-t1)+"ms");
        long t2 = System.currentTimeMillis();
        ForkJoinPool.commonPool().invoke(new ParallelMergeSort(arr, 0, arr.length));
        System.out.println("Parallel: "+(System.currentTimeMillis()-t2)+"ms");
        System.out.println("Correct: "+Arrays.equals(arr, copy));
    }
}

