import java.util.concurrent.atomic.*;

public class Q8 {
    static class LockFreeQueue<T> {
        private static class Node<T> {
            final T value;
            final AtomicReference<Node<T>> next = new AtomicReference<>(null);
            Node(T value) { this.value = value; }
        }
        private final AtomicReference<Node<T>> head;
        private final AtomicReference<Node<T>> tail;

        LockFreeQueue() {
            Node<T> sentinel = new Node<>(null);
            head = new AtomicReference<>(sentinel);
            tail = new AtomicReference<>(sentinel);
        }

        public void enqueue(T value) {
            Node<T> newNode = new Node<>(value);
            while (true) {
                Node<T> t = tail.get();
                Node<T> next = t.next.get();
                if (t == tail.get()) { // consistent read
                    if (next == null) {
                        if (t.next.compareAndSet(null, newNode)) {
                            tail.compareAndSet(t, newNode); // advance tail
                            return;
                        }
                    } else {
                        tail.compareAndSet(t, next); // help advance stale tail
                    }
                }
            }
        }

        public T dequeue() {
            while (true) {
                Node<T> h    = head.get();
                Node<T> t    = tail.get();
                Node<T> next = h.next.get();
                if (h == head.get()) {
                    if (h == t) {
                        if (next == null) return null; // empty
                        tail.compareAndSet(t, next);  // advance stale tail
                    } else {
                        T value = next.value;
                        if (head.compareAndSet(h, next)) return value;
                    }
                }
            }
        }
    }

    public static void main(String[] args) throws InterruptedException {
        LockFreeQueue<Integer> queue = new LockFreeQueue<>();
        Thread[] producers = new Thread[4];
        for (int i=0;i<4;i++) { final int base=i*25;
            producers[i] = new Thread(() -> { for(int j=1;j<=25;j++) queue.enqueue(base+j); });
        }
        for (Thread t : producers) t.start();
        for (Thread t : producers) t.join();
        int count=0; while(queue.dequeue()!=null) count++;
        System.out.println("Dequeued: "+count+" (expected 100)");
    }
}

