import java.util.concurrent.*;
import java.util.*;

public class Q17 {
    public static void main(String[] args) throws InterruptedException {
        Exchanger<List<Integer>> exchanger = new Exchanger<>();
        int BATCHES = 3, BATCH_SIZE = 5;

        Thread producer = new Thread(() -> {
            try {
                List<Integer> buffer = new ArrayList<>();
                int value = 1;
                for (int b = 0; b < BATCHES; b++) {
                    for (int i = 0; i < BATCH_SIZE; i++) buffer.add(value++);
                    System.out.println("Producer sending batch: " + buffer);
                    buffer = exchanger.exchange(buffer); // swap full for empty
                    buffer.clear();
                }
            } catch (InterruptedException e) { Thread.currentThread().interrupt(); }
        });

        Thread consumer = new Thread(() -> {
            try {
                List<Integer> buffer = new ArrayList<>();
                for (int b = 0; b < BATCHES; b++) {
                    buffer = exchanger.exchange(buffer); // receive full buffer
                    int sum = buffer.stream().mapToInt(Integer::intValue).sum();
                    System.out.println("Consumer received batch, sum=" + sum);
                }
            } catch (InterruptedException e) { Thread.currentThread().interrupt(); }
        });

        producer.start(); consumer.start();
        producer.join();  consumer.join();
    }
}

