import java.util.concurrent.*;
import java.util.*;

public class Q18 {
    public static <T> Optional<T> fetchWithTimeout(Callable<T> task, long timeoutMs) {
        try {
            T result = CompletableFuture
                .supplyAsync(() -> {
                    try { return task.call(); }
                    catch (Exception e) { throw new RuntimeException(e); }
                })
                .completeOnTimeout(null, timeoutMs, TimeUnit.MILLISECONDS)
                .join();
            return Optional.ofNullable(result);
        } catch (Exception e) {
            return Optional.empty();
        }
    }

    public static void main(String[] args) throws Exception {
        Optional<String> fast = fetchWithTimeout(() -> { Thread.sleep(50); return "fast result"; }, 200);
        System.out.println("Fast: " + fast);

        Optional<String> slow = fetchWithTimeout(() -> { Thread.sleep(500); return "slow result"; }, 100);
        System.out.println("Slow: " + slow);
    }
}

