public class Q19 {
    static volatile boolean runningVolatile = true;
    static volatile int volatileCounter = 0;

    public static void main(String[] args) throws InterruptedException {
        // Test 1: volatile ensures visibility
        Thread reader = new Thread(() -> {
            int count = 0;
            while (runningVolatile) count++; // always reads from main memory
            System.out.println("Reader stopped after " + count + " iterations");
        });
        reader.start();
        Thread.sleep(5);
        runningVolatile = false; // write immediately visible to reader
        reader.join(1000);
        System.out.println("Reader stopped: " + !reader.isAlive());

        // Test 2: volatile ++ is NOT atomic
        int THREADS = 4, OPS = 10_000;
        Thread[] ts = new Thread[THREADS];
        for (int i=0;i<THREADS;i++) ts[i] = new Thread(() -> { for(int j=0;j<OPS;j++) volatileCounter++; });
        for (Thread t : ts) t.start();
        for (Thread t : ts) t.join();
        System.out.println("Volatile counter (expected "+THREADS*OPS+"): " + volatileCounter);
        System.out.println("Race condition: " + (volatileCounter < THREADS*OPS));
    }
}

