import java.util.concurrent.*;
import java.util.*;

public class Q20 {
    public static void main(String[] args) throws InterruptedException {
        int N = 10_000;

        // Virtual threads — Java 21+
        long t1 = System.currentTimeMillis();
        CountDownLatch latch1 = new CountDownLatch(N);
        for (int i = 0; i < N; i++) {
            Thread.ofVirtual().start(() -> {
                try { Thread.sleep(100); }
                catch (InterruptedException e) { Thread.currentThread().interrupt(); }
                finally { latch1.countDown(); }
            });
        }
        latch1.await();
        System.out.println(N+" virtual threads in "+(System.currentTimeMillis()-t1)+"ms (~100ms)");

        // Platform thread pool — 200 threads
        long t2 = System.currentTimeMillis();
        CountDownLatch latch2 = new CountDownLatch(N);
        ExecutorService pool = Executors.newFixedThreadPool(200);
        for (int i = 0; i < N; i++) {
            pool.submit(() -> {
                try { Thread.sleep(100); latch2.countDown(); }
                catch (InterruptedException e) { Thread.currentThread().interrupt(); }
            });
        }
        latch2.await(); pool.shutdown();
        System.out.println(N+" platform threads (200 pool) in "+(System.currentTimeMillis()-t2)+"ms (~5000ms)");

        // Also demonstrate virtual thread executor
        try (ExecutorService vte = Executors.newVirtualThreadPerTaskExecutor()) {
            List<Future<String>> futures = new ArrayList<>();
            for (int i = 0; i < 100; i++) {
                final int id = i;
                futures.add(vte.submit(() -> { Thread.sleep(10); return "vt-"+id; }));
            }
            long count = futures.stream().filter(f -> { try{f.get();return true;}catch(Exception e){return false;} }).count();
            System.out.println("Virtual executor tasks completed: " + count);
        }
    }
}
